<script lang="ts">
  import { onMount, tick } from 'svelte';
  import { Dialog } from 'bits-ui';

  type Message = { id: string; channel: string; username: string; text: string; created_at: number; edited: boolean; deleted?: boolean };
  type Participant = { user_id: string; username: string; roles: string[]; online: boolean };
  type User = { id: string; email: string; username: string; roles: string[]; permissions: string[]; disabled_at?: number | null };
  type AdminChannel = { id: string; name: string; description: string; created_at: number; archived_at?: number | null; deleted_at?: number | null; retention_days: number };
  type AdminMessage = Message & { deleted_at?: number | null; deleted_by?: string | null; deletion_reason?: string | null };
  type Conversation = { id: string; name: string; kind: 'public' | 'private' | 'direct'; owner_user_id?: string | null; display_name: string; peer_user_id?: string | null; peer_username?: string | null };
  type Member = { user_id: string; username: string; membership_role: string };
  type Event = { type: string; username?: string; channels?: string[]; conversations?: Conversation[]; members?: Member[]; name?: string; channel?: string; messages?: Message[]; message?: Message; error?: string; participants?: Participant[]; participant?: Participant; user_id?: string; source?: 'cache' | 'database'; has_more?: boolean; [key: string]: unknown };
  type AdminTab = 'overview' | 'users' | 'roles' | 'channels' | 'moderation' | 'participants' | 'audit' | 'operations';

  let authUser: User | null = null;
  let authMode: 'login' | 'register' = 'login';
  let authEmail = '', authUsername = '', authPassword = '', csrf = '';
  let activeView: 'chat' | 'admin' = 'chat';
  let adminTab: AdminTab = 'overview';
  let adminUsers: User[] = [], adminRoles: { role: string; permissions: string[] }[] = [], audit: { id: string; action: string; target_type: string; created_at: number }[] = [], adminChannels: AdminChannel[] = [], adminMessages: AdminMessage[] = [], adminParticipants: Participant[] = [];
  let operations: Record<string, string | number> = {};
  let channels = ['main'], privateConversations: Conversation[] = [], channelMembers: Member[] = [], activeChannel = 'main', activeConversation: Conversation | null = null, filter = '', newChannel = '';
  let messages: Message[] = [], participants: Participant[] = [], draft = '', editingId: string | null = null, editDraft = '', historyHasMore = false, olderHistoryLoading = false, lastHistorySource: 'cache' | 'database' | null = null;
  let socket: WebSocket | undefined, viewport: HTMLDivElement, reconnectTimer: ReturnType<typeof setTimeout>, heartbeatTimer: ReturnType<typeof setInterval>;
  let status: 'connecting' | 'connected' | 'disconnected' = 'connecting', pendingChannel: string | null = null, historyLoading = true, showJump = false, notice = '', intentionalClose = false, reconnectDelay = 1000;
  let mobilePanel: 'channels' | 'participants' | null = null;
  let createMode: 'menu' | 'public' | 'private' | 'dm' | null = null, memberOpen = false, userSearch = '', userResults: { id: string; username: string }[] = [], directoryUsers: { id: string; username: string }[] = [], searchTimer: ReturnType<typeof setTimeout>, directorySearchTimer: ReturnType<typeof setTimeout>;

  $: visibleChannels = channels.filter((item) => item.toLowerCase().includes(filter.trim().toLowerCase()));
  $: isAdmin = Boolean(authUser?.permissions.includes('users:read'));

  async function request(url: string, init: RequestInit = {}) {
    const response = await fetch(url, { ...init, credentials: 'include', headers: { ...(init.body ? { 'content-type': 'application/json' } : {}), ...(init.headers ?? {}) } });
    const body = await response.json().catch(() => null);
    if (!response.ok) throw new Error(body?.error ?? body?.message ?? `Request failed (${response.status})`);
    return { response, body };
  }

  async function authenticate() {
    try {
      const body = authMode === 'login' ? { email: authEmail, password: authPassword } : { email: authEmail, username: authUsername, password: authPassword };
      const result = await request(`/api/v1/auth/${authMode}`, { method: 'POST', body: JSON.stringify(body) });
      authUser = result.body; csrf = result.response.headers.get('x-csrf-token') ?? ''; authPassword = ''; notice = ''; intentionalClose = false; connect(); if (result.body.permissions.includes('users:read')) void loadAdmin();
    } catch (error) { notice = error instanceof Error ? error.message : 'Authentication failed'; }
  }

  async function bootstrap() { try { const result = await request('/api/v1/auth/me'); authUser = result.body; csrf = result.response.headers.get('x-csrf-token') ?? ''; intentionalClose = false; connect(); if (result.body.permissions.includes('users:read')) void loadAdmin(); } catch { /* signed out */ } }

  async function loadAdmin() {
    try {
      const [users, roles, log, ops, channelList, messageList, participantList] = await Promise.all([request('/api/v1/admin/users'), request('/api/v1/admin/roles'), request('/api/v1/admin/audit'), request('/api/v1/admin/operations'), request('/api/v1/admin/channels'), request('/api/v1/admin/messages?limit=100'), request('/api/v1/admin/participants/main')]);
      adminUsers = users.body.items ?? users.body; adminRoles = roles.body.roles ?? []; audit = log.body.items ?? log.body; operations = ops.body; adminChannels = channelList.body.items ?? []; adminMessages = messageList.body.items ?? []; adminParticipants = participantList.body.items ?? participantList.body ?? [];
    } catch (error) { notice = error instanceof Error ? error.message : 'Unable to load administration data'; }
  }

  async function toggleUser(user: User) {
    try { await request(`/api/v1/admin/users/${user.id}/${user.disabled_at ? 'enable' : 'disable'}`, { method: 'POST', headers: { 'x-csrf-token': csrf } }); await loadAdmin(); notice = `${user.username} updated`; } catch (error) { notice = error instanceof Error ? error.message : 'Action failed'; }
  }

  async function moderateMessage(id: string, action: 'delete' | 'restore') { try { await request(`/api/v1/admin/messages/${id}/${action}`, { method: 'POST', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ reason: 'Admin action' }) }); await loadAdmin(); notice = 'Message updated'; } catch (error) { notice = error instanceof Error ? error.message : 'Action failed'; } }
  async function setChannelState(id: string, action: 'archive' | 'restore' | 'delete' | 'undelete') { try { await request(`/api/v1/admin/channels/${id}/${action}`, { method: 'POST', headers: { 'x-csrf-token': csrf } }); await loadAdmin(); notice = 'Channel updated'; } catch (error) { notice = error instanceof Error ? error.message : 'Action failed'; } }
  async function logout() { try { await request('/api/v1/auth/logout', { method: 'POST', headers: { 'x-csrf-token': csrf } }); } finally { intentionalClose = true; socket?.close(); authUser = null; } }

  function wsUrl() { if (import.meta.env.VITE_WS_URL) return import.meta.env.VITE_WS_URL; const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:'; return `${protocol}//${location.hostname}:3000/api/v1/ws`; }
  function connect() {
    if (intentionalClose) return; status = 'connecting'; historyLoading = true;
    try { socket = new WebSocket(wsUrl()); } catch { disconnected(); return; }
    socket.onopen = () => { status = 'connected'; reconnectDelay = 1000; notice = ''; send({ type: 'heartbeat' }); clearInterval(heartbeatTimer); heartbeatTimer = setInterval(() => send({ type: 'heartbeat' }), 15000); };
    socket.onclose = disconnected;
    socket.onerror = () => { notice = 'Connection interrupted. Reconnecting…'; };
    socket.onmessage = ({ data }) => { try { handle(JSON.parse(data) as Event); } catch { notice = 'Received an invalid server event'; } };
  }
  function disconnected() { if (intentionalClose) return; status = 'disconnected'; historyLoading = false; notice = 'Unable to reach the chat service. Retrying…'; clearTimeout(reconnectTimer); reconnectTimer = setTimeout(connect, reconnectDelay); reconnectDelay = Math.min(reconnectDelay * 1.7, 10000); }
  function send(event: object) { if (!socket || socket.readyState !== WebSocket.OPEN) return false; socket.send(JSON.stringify(event)); return true; }
  function handle(event: Event) {
    if (event.type === 'welcome') authUser = authUser ? { ...authUser, username: event.username ?? authUser.username } : authUser;
    if (event.type === 'channels') channels = sort(event.channels ?? ['main']);
    if (event.type === 'private_conversations') privateConversations = (event.conversations ?? []).filter((conversation) => conversation.kind !== 'public');
    if (event.type === 'members' && event.channel === activeChannel) channelMembers = event.members ?? [];
    if (event.type === 'channel_created' && event.name) channels = sort([...channels, event.name]);
    if (event.type === 'channel_deleted' && event.name) { channels = channels.filter((item) => item !== event.name); if (activeChannel === event.name) join('main'); }
    if (event.type === 'joined' && event.name) { activeChannel = event.name; activeConversation = privateConversations.find((item) => item.name === event.name) ?? null; pendingChannel = null; messages = []; participants = []; channelMembers = []; editingId = null; historyHasMore = false; olderHistoryLoading = false; lastHistorySource = null; historyLoading = true; }
    if ((event.type === 'presence_sync' || event.type === 'participants') && event.channel === activeChannel) participants = event.participants ?? [];
    if (event.type === 'participant_joined' && event.channel === activeChannel && event.participant) participants = [...participants.filter((item) => item.user_id !== event.participant?.user_id), event.participant];
    if (event.type === 'participant_left' && event.channel === activeChannel && event.user_id) participants = participants.filter((item) => item.user_id !== event.user_id);
    if (event.type === 'history' && event.channel === activeChannel) { messages = event.messages ?? []; historyHasMore = Boolean(event.has_more); olderHistoryLoading = false; lastHistorySource = event.source ?? null; historyLoading = false; void scrollLatest(); }
    if (event.type === 'history_page' && event.channel === activeChannel) { const beforeHeight = viewport?.scrollHeight ?? 0; const older = event.messages ?? []; messages = [...older, ...messages.filter((message) => !older.some((item) => item.id === message.id))]; historyHasMore = Boolean(event.has_more); olderHistoryLoading = false; lastHistorySource = event.source ?? null; void tick().then(() => { if (viewport) viewport.scrollTop += viewport.scrollHeight - beforeHeight; }); }
    if (event.type === 'message' && event.message?.channel === activeChannel && !messages.some((item) => item.id === event.message?.id)) { const near = nearBottom(); messages = [...messages, event.message]; void tick().then(() => { if (near) void scrollLatest(); }); }
    if (event.type === 'message_updated' && event.message) messages = messages.map((item) => item.id === event.message?.id ? event.message as Message : item);
    if (event.type === 'error') notice = event.error ?? String(event.message ?? 'The server rejected that action');
  }
  function sort(items: string[]) { return [...new Set(items)].sort((a, b) => a === 'main' ? -1 : b === 'main' ? 1 : a.localeCompare(b)); }
  function join(name: string) { if (name === activeChannel && !pendingChannel) return; if (send({ type: 'join_channel', name })) { pendingChannel = name; historyLoading = true; mobilePanel = null; } }
  function submit() { const text = draft.trim(); if (text && status === 'connected' && !historyLoading && send({ type: 'send_message', text })) draft = ''; }
  function loadOlderHistory() { const oldest = messages[0]; if (!oldest || !historyHasMore || olderHistoryLoading || status !== 'connected') return; const requestedChannel = activeChannel; if (send({ type: 'load_history', channel: requestedChannel, before_created_at: oldest.created_at, before_id: oldest.id })) olderHistoryLoading = true; }
  function closeCreate() { createMode = null; newChannel = ''; userSearch = ''; userResults = []; }
  function create() { const name = newChannel.trim().toLowerCase(); if (name && send({ type: 'create_channel', name })) { closeCreate(); } }
  function createPrivate() { const name = newChannel.trim().toLowerCase(); if (name && send({ type: 'create_private_channel', name })) { closeCreate(); } }
  function openDirect(userId: string) { if (send({ type: 'open_direct', user_id: userId })) { pendingChannel = '__direct__'; closeCreate(); } }
  function searchForUsers() { clearTimeout(searchTimer); searchTimer = setTimeout(async () => { if (userSearch.trim().length < 1) { userResults = []; return; } try { const result = await request(`/api/v1/users/search?q=${encodeURIComponent(userSearch.trim())}`); userResults = result.body; } catch { userResults = []; } }, 180); }
  function searchDirectory() { clearTimeout(directorySearchTimer); const term = filter.trim(); if (!term) { directoryUsers = []; return; } directorySearchTimer = setTimeout(async () => { try { const result = await request(`/api/v1/users/search?q=${encodeURIComponent(term)}`); directoryUsers = result.body; } catch { directoryUsers = []; } }, 180); }
  function openMemberDialog() { userSearch = ''; userResults = []; memberOpen = true; }
  async function inviteMember(userId: string) { try { await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/members`, { method: 'POST', headers: { 'x-csrf-token': csrf }, body: JSON.stringify({ user_id: userId }) }); memberOpen = false; const result = await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/members`); channelMembers = result.body; notice = 'Member invited'; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to invite member'; } }
  async function removeMember(userId: string) { try { await request(`/api/v1/channels/${encodeURIComponent(activeChannel)}/members/${userId}`, { method: 'DELETE', headers: { 'x-csrf-token': csrf } }); channelMembers = channelMembers.filter((member) => member.user_id !== userId); notice = 'Member removed'; } catch (error) { notice = error instanceof Error ? error.message : 'Unable to remove member'; } }
  function removeChannel(name: string) { if (name !== 'main' && confirm(`Delete #${name}?`)) send({ type: 'delete_channel', name }); }
  function saveEdit() { const text = editDraft.trim(); if (editingId && text && send({ type: 'edit_message', id: editingId, text })) { editingId = null; editDraft = ''; } }
  function deleteMessage(id: string) { if (confirm('Delete this message?')) send({ type: 'delete_message', id }); }
  function nearBottom() { return !viewport || viewport.scrollHeight - viewport.scrollTop - viewport.clientHeight < 120; }
  function scrollState() { showJump = !nearBottom(); if (viewport && viewport.scrollTop < 140) loadOlderHistory(); }
  async function scrollLatest() { await tick(); if (viewport) viewport.scrollTop = viewport.scrollHeight; showJump = false; }
  function time(value: number) { return new Date(value).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }

  onMount(() => { void bootstrap(); return () => { intentionalClose = true; clearTimeout(reconnectTimer); clearInterval(heartbeatTimer); socket?.close(); }; });
</script>

<svelte:head><title>vussa workspace</title><meta name="description" content="A focused realtime team workspace" /></svelte:head>

{#if !authUser}
  <main class="auth-layout"><section class="auth-panel"><div class="brand-mark">✦</div><p class="kicker">vussa workspace</p><h1>{authMode === 'login' ? 'Make space for better conversations.' : 'Create your workspace account.'}</h1><p class="auth-copy">A calm, focused place for teams to share ideas and keep work moving.</p><form onsubmit={(event) => { event.preventDefault(); void authenticate(); }}><label>Email or username<input bind:value={authEmail} placeholder="you@example.com" required /></label>{#if authMode === 'register'}<label>Username<input bind:value={authUsername} placeholder="your-handle" required /></label>{/if}<label>Password<input bind:value={authPassword} type="password" placeholder="Your password" required /></label><button class="primary-button" type="submit">{authMode === 'login' ? 'Sign in' : 'Create account'} <span>↗</span></button></form><button class="link-button" onclick={() => authMode = authMode === 'login' ? 'register' : 'login'}>{authMode === 'login' ? 'Need an account?' : 'Already have an account?'}</button>{#if notice}<p class="form-error">{notice}</p>{/if}</section><aside class="auth-art"><div class="art-orb orb-one"></div><div class="art-orb orb-two"></div><div class="art-card"><span class="status-dot"></span><strong>Live conversations</strong><span>Stay close to the work.</span></div></aside></main>
{:else}
  <main class="app-shell">
    <header class="topbar"><button class="mobile-menu" aria-label="Open channels" onclick={() => mobilePanel = 'channels'}>☰</button><a class="brand" href="/" aria-label="vussa home"><span class="brand-mark small">✦</span><span><b>vussa</b><small>workspace</small></span></a><div class="topbar-center"><button class:active={activeView === 'chat'} onclick={() => activeView = 'chat'}>Chat</button>{#if isAdmin}<button class:active={activeView === 'admin'} onclick={() => activeView = 'admin'}>Admin</button>{/if}</div><div class="topbar-actions"><span class="connection" class:online={status === 'connected'}><i></i>{status === 'connected' ? 'Live' : status === 'connecting' ? 'Connecting' : 'Offline'}</span><div class="account"><span class="avatar">{authUser.username.slice(0, 1).toUpperCase()}</span><span class="account-name">{authUser.username}</span><button aria-label="Sign out" onclick={() => void logout()}>↪</button></div></div></header>
    {#if notice}<div class="toast" role="status"><span>!</span>{notice}<button onclick={() => notice = ''} aria-label="Dismiss">×</button></div>{/if}
    {#if activeView === 'admin' && isAdmin}
      <section class="admin-shell"><aside class="admin-nav"><div><p class="kicker">Control room</p><h1>Administration</h1></div>{#each [['overview','Overview','⌂'],['users','Users','♙'],['roles','Roles & access','◈'],['channels','Channels','#'],['moderation','Moderation','⌁'],['participants','Participants','●'],['audit','Audit log','≡'],['operations','Operations','⌘']] as item}<button class:active={adminTab === item[0]} onclick={() => adminTab = item[0] as AdminTab}><span>{item[2]}</span>{item[1]}</button>{/each}</aside><section class="admin-content"><div class="section-heading"><div><p class="kicker">Workspace controls</p><h2>{adminTab[0].toUpperCase() + adminTab.slice(1)}</h2></div><span class="permission-badge">Authorized</span></div>{#if adminTab === 'overview'}<div class="metric-grid"><div><small>Active users</small><strong>{operations.active_users ?? '—'}</strong><span>currently enabled</span></div><div><small>WebSockets</small><strong>{operations.websockets ?? '—'}</strong><span>live connections</span></div><div><small>Outbox</small><strong>{operations.outbox_pending ?? '—'}</strong><span>pending events</span></div><div><small>Services</small><strong class="good">Healthy</strong><span>PostgreSQL · Valkey</span></div></div><div class="welcome-card"><span class="welcome-icon">✦</span><div><h3>Everything in one place.</h3><p>Use the sections on the left to manage accounts, access, channels, and operational health.</p></div></div>{:else if adminTab === 'users'}<div class="table-card"><div class="table-toolbar"><input placeholder="Search users" aria-label="Search users" /><span>{adminUsers.length} users</span></div><div class="table-scroll"><table><thead><tr><th>User</th><th>Role</th><th>Status</th><th></th></tr></thead><tbody>{#each adminUsers as user}<tr><td><strong>{user.username}</strong><small>{user.email}</small></td><td>{#each user.roles as role}<span class="role-pill">{role}</span>{/each}</td><td><span class:good={!user.disabled_at} class="state-pill">{user.disabled_at ? "Disabled" : "Active"}</span></td><td>{#if user.id !== authUser.id}<button class="row-action" onclick={() => void toggleUser(user)}>{user.disabled_at ? "Enable" : "Disable"}</button>{/if}</td></tr>{:else}<tr><td colspan="4" class="empty-cell">No users found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === 'roles'}<div class="table-card"><div class="table-toolbar"><span>Fixed roles and permissions</span></div><div class="table-scroll"><table><thead><tr><th>Role</th><th>Permissions</th></tr></thead><tbody>{#each adminRoles as role}<tr><td><strong>{role.role}</strong></td><td>{role.permissions.join(' · ') || 'No permissions assigned'}</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === 'audit'}<div class="table-card"><div class="table-toolbar"><span>Recent activity</span><span>{audit.length} events</span></div><div class="table-scroll"><table><thead><tr><th>Action</th><th>Target</th><th>Time</th></tr></thead><tbody>{#each audit as event}<tr><td><strong>{event.action}</strong></td><td>{event.target_type}</td><td>{new Date(event.created_at).toLocaleString()}</td></tr>{:else}<tr><td colspan="3" class="empty-cell">No audit activity yet.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === 'operations'}<div class="metric-grid compact">{#each Object.entries(operations) as pair}<div><small>{pair[0].replaceAll('_', ' ')}</small><strong>{pair[1]}</strong></div>{/each}</div>{:else if adminTab === "channels"}<div class="table-card"><div class="table-toolbar"><span>Workspace channels</span><span>{adminChannels.length} channels</span></div><div class="table-scroll"><table><thead><tr><th>Channel</th><th>Retention</th><th>State</th><th></th></tr></thead><tbody>{#each adminChannels as channel}<tr><td><strong>#{channel.name}</strong><small>{channel.description || "No description"}</small></td><td>{channel.retention_days} days</td><td><span class="state-pill">{channel.deleted_at ? "Deleted" : channel.archived_at ? "Archived" : "Active"}</span></td><td>{#if channel.name !== "main"}<button class="row-action" onclick={() => void setChannelState(channel.id, channel.archived_at ? "restore" : "archive")}>{channel.archived_at ? "Restore" : "Archive"}</button>{/if}</td></tr>{:else}<tr><td colspan="4" class="empty-cell">No channels found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === "moderation"}<div class="table-card"><div class="table-toolbar"><span>Message moderation</span><span>{adminMessages.length} messages</span></div><div class="table-scroll"><table><thead><tr><th>Message</th><th>Channel</th><th>Author</th><th>State</th><th></th></tr></thead><tbody>{#each adminMessages as message}<tr><td><strong>{message.text}</strong><small>{new Date(message.created_at).toLocaleString()}</small></td><td>#{message.channel}</td><td>{message.username}</td><td><span class="state-pill">{message.deleted_at ? "Deleted" : "Visible"}</span></td><td><button class="row-action" onclick={() => void moderateMessage(message.id, message.deleted_at ? "restore" : "delete")}>{message.deleted_at ? "Restore" : "Delete"}</button></td></tr>{:else}<tr><td colspan="5" class="empty-cell">No messages found.</td></tr>{/each}</tbody></table></div></div>{:else if adminTab === "participants"}<div class="table-card"><div class="table-toolbar"><span>Online participants in #main</span><span>{adminParticipants.length} online</span></div><div class="table-scroll"><table><thead><tr><th>User</th><th>Role</th><th>Status</th></tr></thead><tbody>{#each adminParticipants as person}<tr><td><strong>{person.username}</strong></td><td>{person.roles.join(" · ") || "user"}</td><td><span class="state-pill good">Online</span></td></tr>{:else}<tr><td colspan="3" class="empty-cell">No online participants.</td></tr>{/each}</tbody></table></div></div>{/if}</section></section>
    {:else}
      <section class="workspace"><aside class="channel-sidebar" class:drawer-open={mobilePanel === 'channels'}><div class="sidebar-heading"><div><p class="kicker">Your workspace</p><h2>Channels <span>{channels.length}</span></h2></div><button class="icon-button" onclick={() => createMode = createMode === 'menu' ? null : 'menu'} aria-label="Create conversation">＋</button></div>{#if createMode}<div class="create-menu">{#if createMode === 'menu'}<p class="kicker">Create</p><button onclick={() => createMode = 'public'}><span class="create-symbol">#</span><span><strong>Public channel</strong><small>Everyone can find it</small></span></button><button onclick={() => createMode = 'private'}><span class="create-symbol">▣</span><span><strong>Private channel</strong><small>Invite members only</small></span></button><button onclick={() => { createMode = 'dm'; userSearch = ''; userResults = []; }}><span class="create-symbol">↗</span><span><strong>Direct message</strong><small>Start a private chat</small></span></button>{:else if createMode === 'public' || createMode === 'private'}<p class="kicker">{createMode === 'private' ? 'Private channel' : 'Public channel'}</p><input bind:value={newChannel} placeholder="channel-name" maxlength="40" onkeydown={(event) => event.key === 'Enter' && (createMode === 'private' ? createPrivate() : create())} /><div class="create-actions"><button class="secondary-button" onclick={() => createMode = 'menu'}>Back</button><button class="primary-button" onclick={() => createMode === 'private' ? createPrivate() : create()}>Create</button></div>{:else}<p class="kicker">Direct message</p><input bind:value={userSearch} oninput={searchForUsers} placeholder="Search people" aria-label="Search people" /><div class="user-results">{#each userResults as result}<button class="create-user" type="button" onclick={() => openDirect(result.id)}><span class="avatar">{result.username.slice(0, 1).toUpperCase()}</span><span>{result.username}</span></button>{:else}<small class="create-hint">Type a name to search.</small>{/each}</div><button class="secondary-button create-back" onclick={() => createMode = 'menu'}>Back</button>{/if}</div>{/if}<label class="search"><span>⌕</span><input bind:value={filter} oninput={searchDirectory} placeholder="Find a channel or person" aria-label="Find a channel or person" /></label><nav class="channel-list">{#each visibleChannels as channel}<div class="channel-row" class:active={channel === activeChannel}><button onclick={() => join(channel)}><span class="hash">#</span><span>{channel}</span></button>{#if channel !== 'main'}<button class="delete-channel" onclick={() => removeChannel(channel)} aria-label={`Delete ${channel}`}>×</button>{/if}</div>{:else}<p class="muted">No matching channels</p>{/each}</nav>{#if filter.trim() && directoryUsers.length}<div class="directory-results"><p class="kicker">People</p>{#each directoryUsers as person}<button class="directory-user" onclick={() => { openDirect(person.id); filter = ""; directoryUsers = []; }}><span class="avatar">{person.username.slice(0, 1).toUpperCase()}</span><span>{person.username}</span><small>Direct message</small></button>{/each}</div>{/if}<div class="private-section"><p class="kicker">Private conversations</p>{#each privateConversations as conversation}<div class="channel-row" class:active={conversation.name === activeChannel}><button onclick={() => join(conversation.name)}><span class="hash">{conversation.kind === "direct" ? "↗" : "▣"}</span><span>{conversation.display_name}</span></button></div>{:else}<p class="muted">No private conversations</p>{/each}</div><button class="mobile-close" onclick={() => mobilePanel = null}>Close</button></aside><section class="chat"><header class="chat-header"><div class="channel-heading"><span class="channel-icon">#</span><div><h2>{activeConversation?.display_name ?? activeChannel}</h2><p>{historyLoading ? 'Loading messages…' : activeConversation ? `${messages.length} messages · ${channelMembers.length} members` : `${messages.length} messages in this channel`}</p></div></div><button class="participant-toggle" onclick={() => mobilePanel = 'participants'}><span class="presence-ring"></span>{participants.length} online</button></header><div class="message-area" bind:this={viewport} onscroll={scrollState} role="log" aria-live="polite">{#if historyLoading}<div class="state"><div class="spinner"></div><p>Opening #{activeChannel}</p></div>{:else if messages.length === 0}<div class="state"><span class="state-icon">✦</span><h3>Start the conversation</h3><p>Be the first person to say something in #{activeChannel}.</p></div>{:else}<div class="messages">{#each messages as message (message.id)}<article class="message"><span class="avatar">{message.username.slice(0, 1).toUpperCase()}</span><div class="message-body"><div class="message-meta"><strong>{message.username}</strong><time>{time(message.created_at)}</time>{#if message.edited}<span>edited</span>{/if}</div>{#if editingId === message.id}<form class="edit-box" onsubmit={(event) => { event.preventDefault(); saveEdit(); }}><input bind:value={editDraft} aria-label="Edit message" maxlength="2000" /><button type="submit">Save</button><button type="button" onclick={() => editingId = null}>Cancel</button></form>{:else}<p>{message.text}</p>{#if message.username === authUser.username}<button class="edit-link" onclick={() => { editingId = message.id; editDraft = message.text; }}>Edit</button>{/if}{/if}</div></article>{/each}</div>{/if}{#if showJump}<button class="jump" onclick={scrollLatest}>↓ Jump to latest</button>{/if}</div><form class="composer" onsubmit={(event) => { event.preventDefault(); submit(); }}><div><input bind:value={draft} disabled={status !== 'connected' || historyLoading} maxlength="2000" placeholder={activeConversation ? `Message ${activeConversation.display_name}` : `Message #${activeChannel}`} aria-label="Message composer" /><span>{draft.length}/2000</span></div><button class="send" disabled={!draft.trim() || status !== 'connected' || historyLoading} aria-label="Send message">↑</button></form></section><aside class="participant-sidebar" class:drawer-open={mobilePanel === 'participants'}><div class="sidebar-heading"><div><p class="kicker">Channel members</p><h2>Online <span>{participants.length}</span></h2></div><span class="presence-ring"></span></div>{#if activeConversation}<div class="member-list conversation-members"><p class="kicker">Members</p>{#each channelMembers as member}<div class="member"><span class="avatar">{member.username.slice(0, 1).toUpperCase()}</span><div><strong>{member.username}</strong><small>{member.membership_role}</small></div>{#if activeConversation.owner_user_id === authUser.id && member.membership_role !== "owner"}<button class="delete-channel" onclick={() => void removeMember(member.user_id)} aria-label={`Remove ${member.username}`}>×</button>{/if}</div>{/each}{#if activeConversation.owner_user_id === authUser.id}<button class="secondary-button private-action" onclick={openMemberDialog}>＋ Invite member</button>{/if}</div>{/if}<div class="member-list">{#each participants as person}<div class="member"><span class="avatar">{person.username.slice(0, 1).toUpperCase()}</span><div><strong>{person.username}</strong><small>{person.roles.join(' · ') || 'user'}</small></div><i></i></div>{:else}<p class="muted">No one is online yet.</p>{/each}</div><button class="mobile-close" onclick={() => mobilePanel = null}>Close</button></aside></section>
    {/if}
    <Dialog.Root bind:open={memberOpen}><Dialog.Portal><Dialog.Overlay class="dialog-overlay" /><Dialog.Content class="dialog"><Dialog.Title>Invite a member</Dialog.Title><Dialog.Description>Only invited users can access this private channel.</Dialog.Description><input bind:value={userSearch} oninput={searchForUsers} placeholder="Search by username" aria-label="Search members" /><div class="user-results">{#each userResults as result}<button class="row-action user-result" type="button" onclick={() => void inviteMember(result.id)}>{result.username}</button>{:else}<p class="muted">Search for a user to invite.</p>{/each}</div><div class="dialog-actions"><Dialog.Close class="secondary-button">Cancel</Dialog.Close></div></Dialog.Content></Dialog.Portal></Dialog.Root></main>
{/if}

